import { calculateHaversineDistance, EARTH_RADIUS_METERS } from '../utils'

/**
 * Utilities for constraining marker movement based on draggable directions
 */

function getDirectionType({ direction }) {
  if (direction === 'n' || direction === 's') return 'vertical'
  if (direction === 'e' || direction === 'w') return 'horizontal'
  if (direction === 'ns' || direction === 'ew') return 'multi-axis'
  if (direction === 'nesw' || direction === 'nwse') return 'diagonal-line'
  if (direction === 'ne' || direction === 'nw' || direction === 'se' || direction === 'sw') return 'diagonal'

  return 'unknown'
}

function projectToDiagonal({ direction, newPosition, originPosition }) {
  const deltaLatitude = newPosition.latitude - originPosition.latitude
  const deltaLongitude = newPosition.longitude - originPosition.longitude

  const absLatitude = Math.abs(deltaLatitude)
  const absLongitude = Math.abs(deltaLongitude)
  const delta = Math.min(absLatitude, absLongitude)

  const constrainedLatitude = originPosition.latitude + delta * Math.sign(deltaLatitude)
  const constrainedLongitude = originPosition.longitude + delta * Math.sign(deltaLongitude)

  switch (direction) {
    case 'ne':
      if (deltaLatitude > 0 && deltaLongitude > 0) {
        return { latitude: constrainedLatitude, longitude: constrainedLongitude }
      }
      break
    case 'nw':
      if (deltaLatitude > 0 && deltaLongitude < 0) {
        return { latitude: constrainedLatitude, longitude: constrainedLongitude }
      }
      break
    case 'se':
      if (deltaLatitude < 0 && deltaLongitude > 0) {
        return { latitude: constrainedLatitude, longitude: constrainedLongitude }
      }
      break
    case 'sw':
      if (deltaLatitude < 0 && deltaLongitude < 0) {
        return { latitude: constrainedLatitude, longitude: constrainedLongitude }
      }
      break
    default:
      break
  }

  return originPosition
}

function handleMultiAxisConstraint({ draggableDirections, newPosition, originPosition }) {
  const multiAxisDirections = draggableDirections.filter(
    (direction) => getDirectionType({ direction }) === 'multi-axis'
  )

  if (multiAxisDirections.includes('ns') && multiAxisDirections.includes('ew')) {
    return originPosition
  }

  let allowLatitude = false
  let allowLongitude = false

  multiAxisDirections.forEach((direction) => {
    if (direction === 'ns') allowLatitude = true
    if (direction === 'ew') allowLongitude = true
  })

  return {
    latitude: allowLatitude ? newPosition.latitude : originPosition.latitude,
    longitude: allowLongitude ? newPosition.longitude : originPosition.longitude,
  }
}

function handleDiagonalLineConstraint({ diagonalLines, newPosition, originPosition }) {
  if (diagonalLines.length > 1) return originPosition

  const expandedDiagonals = []
  diagonalLines.forEach((line) => {
    if (line === 'nesw') {
      expandedDiagonals.push('ne', 'sw')
    } else if (line === 'nwse') {
      expandedDiagonals.push('nw', 'se')
    }
  })

  let validProjection = null
  expandedDiagonals.forEach((direction) => {
    if (!validProjection) {
      const projected = projectToDiagonal({ newPosition, originPosition, direction })
      if (projected.latitude !== originPosition.latitude || projected.longitude !== originPosition.longitude) {
        validProjection = projected
      }
    }
  })

  return validProjection || originPosition
}

function handleVerticalCardinalConstraint({ draggableDirections, newPosition, originPosition }) {
  const deltaLatitude = newPosition.latitude - originPosition.latitude
  const cardinals = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'vertical')

  if (cardinals.includes('n') && !cardinals.includes('s')) {
    return {
      latitude: deltaLatitude > 0 ? newPosition.latitude : originPosition.latitude,
      longitude: originPosition.longitude,
    }
  }

  if (cardinals.includes('s') && !cardinals.includes('n')) {
    return {
      latitude: deltaLatitude < 0 ? newPosition.latitude : originPosition.latitude,
      longitude: originPosition.longitude,
    }
  }

  return { latitude: newPosition.latitude, longitude: originPosition.longitude }
}

function handleHorizontalCardinalConstraint({ draggableDirections, newPosition, originPosition }) {
  const deltaLongitude = newPosition.longitude - originPosition.longitude
  const cardinals = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'horizontal')

  if (cardinals.includes('e') && !cardinals.includes('w')) {
    return {
      latitude: originPosition.latitude,
      longitude: deltaLongitude > 0 ? newPosition.longitude : originPosition.longitude,
    }
  }

  if (cardinals.includes('w') && !cardinals.includes('e')) {
    return {
      latitude: originPosition.latitude,
      longitude: deltaLongitude < 0 ? newPosition.longitude : originPosition.longitude,
    }
  }

  return { latitude: originPosition.latitude, longitude: newPosition.longitude }
}

function handleDiagonalConstraint({ diagonals, newPosition, originPosition }) {
  const sorted = diagonals.sort().join(',')
  const validDiagonalCombos = new Set(['ne', 'nw', 'se', 'sw', 'ne,sw', 'nw,se'])

  if (!validDiagonalCombos.has(sorted)) return originPosition

  let validProjection = null
  diagonals.forEach((direction) => {
    if (!validProjection) {
      const projected = projectToDiagonal({ newPosition, originPosition, direction })
      if (projected.latitude !== originPosition.latitude || projected.longitude !== originPosition.longitude) {
        validProjection = projected
      }
    }
  })

  return validProjection || originPosition
}

function handleMixedCardinalConstraint({ draggableDirections, newPosition, originPosition }) {
  const verticals = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'vertical')
  const horizontals = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'horizontal')

  if (verticals.length === 2 && horizontals.length === 2) return originPosition

  const deltaLatitude = newPosition.latitude - originPosition.latitude
  const deltaLongitude = newPosition.longitude - originPosition.longitude

  const hasNorth = verticals.includes('n')
  const hasSouth = verticals.includes('s')
  const hasEast = horizontals.includes('e')
  const hasWest = horizontals.includes('w')

  const allowVerticalMovement =
    (hasNorth && hasSouth) || (hasNorth && deltaLatitude > 0) || (hasSouth && deltaLatitude < 0)
  const allowHorizontalMovement =
    (hasEast && hasWest) || (hasEast && deltaLongitude > 0) || (hasWest && deltaLongitude < 0)

  return {
    latitude: allowVerticalMovement ? newPosition.latitude : originPosition.latitude,
    longitude: allowHorizontalMovement ? newPosition.longitude : originPosition.longitude,
  }
}

/**
 * Constrain position to stay within distance bounds
 *
 * @param {Object} params
 * @param {Object} params.newPosition - The new position {latitude, longitude}
 * @param {number} params.newPosition.latitude - Latitude of the new position
 * @param {number} params.newPosition.longitude - Longitude of the new position
 * @param {Object} params.originPosition - The origin position for constraint {latitude, longitude}
 * @param {number} params.originPosition.latitude - Latitude of the origin position
 * @param {number} params.originPosition.longitude - Longitude of the origin position
 * @param {number} [params.maxDistance] - Maximum distance in meters (optional)
 * @param {number} [params.minDistance] - Minimum distance in meters (optional)
 * @returns {Object} result - The constrained position {latitude, longitude}
 * @returns {number} result.latitude - Latitude of the constrained position
 * @returns {number} result.longitude - Longitude of the constrained position
 */
function constrainByDistance({ newPosition, originPosition, maxDistance, minDistance }) {
  const distance = calculateHaversineDistance({
    latitudeOne: originPosition.latitude,
    latitudeTwo: newPosition.latitude,
    longitudeOne: originPosition.longitude,
    longitudeTwo: newPosition.longitude,
  })

  // If within bounds, return as is
  if ((!maxDistance || distance <= maxDistance) && (!minDistance || distance >= minDistance)) {
    return newPosition
  }

  // Calculate the target distance (clamp to min/max)
  let targetDistance = distance
  if (maxDistance && distance > maxDistance) {
    targetDistance = maxDistance
  } else if (minDistance && distance < minDistance) {
    targetDistance = minDistance
  }

  // Calculate the bearing/direction from origin to new position
  const latitude1Radians = (originPosition.latitude * Math.PI) / 180
  const latitude2Radians = (newPosition.latitude * Math.PI) / 180
  const deltaLongitudeRadians = ((newPosition.longitude - originPosition.longitude) * Math.PI) / 180

  const y = Math.sin(deltaLongitudeRadians) * Math.cos(latitude2Radians)
  const x =
    Math.cos(latitude1Radians) * Math.sin(latitude2Radians) -
    Math.sin(latitude1Radians) * Math.cos(latitude2Radians) * Math.cos(deltaLongitudeRadians)
  const bearingRadians = Math.atan2(y, x)

  // Calculate new position at the target distance along the same bearing
  const angularDistance = targetDistance / EARTH_RADIUS_METERS

  const newLatitudeRadians = Math.asin(
    Math.sin(latitude1Radians) * Math.cos(angularDistance) +
      Math.cos(latitude1Radians) * Math.sin(angularDistance) * Math.cos(bearingRadians)
  )

  const newLongitudeRadians =
    (originPosition.longitude * Math.PI) / 180 +
    Math.atan2(
      Math.sin(bearingRadians) * Math.sin(angularDistance) * Math.cos(latitude1Radians),
      Math.cos(angularDistance) - Math.sin(latitude1Radians) * Math.sin(newLatitudeRadians)
    )

  return {
    latitude: (newLatitudeRadians * 180) / Math.PI,
    longitude: (newLongitudeRadians * 180) / Math.PI,
  }
}

/**
 * Constrains a position based on draggable directions and distance bounds
 *
 * @param {Object} params
 * @param {Array<string>} params.draggableDirections - Array of direction strings
 * @param {Object} params.newPosition - The new position {latitude, longitude}
 * @param {number} params.newPosition.latitude - Latitude of the new position
 * @param {number} params.newPosition.longitude - Longitude of the new position
 * @param {Object} params.originPosition - The origin position for constraint {latitude, longitude}
 * @param {number} params.originPosition.latitude - Latitude of the origin position
 * @param {number} params.originPosition.longitude - Longitude of the origin position
 * @param {number} [params.maxDistance] - Maximum distance from originPosition in meters (optional)
 * @param {number} [params.minDistance] - Minimum distance from originPosition in meters (optional)
 * @returns {Object} The constrained position {latitude, longitude}
 */
export function constrainPosition({ draggableDirections, newPosition, originPosition, maxDistance, minDistance }) {
  // First apply directional constraints
  let constrainedPosition = newPosition

  if (draggableDirections && draggableDirections.length > 0) {
    const hasVertical = draggableDirections.some((direction) => getDirectionType({ direction }) === 'vertical')
    const hasHorizontal = draggableDirections.some((direction) => getDirectionType({ direction }) === 'horizontal')
    const hasMultiAxis = draggableDirections.some((direction) => getDirectionType({ direction }) === 'multi-axis')
    const diagonals = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'diagonal')
    const diagonalLines = draggableDirections.filter((direction) => getDirectionType({ direction }) === 'diagonal-line')

    if (hasMultiAxis) {
      constrainedPosition = handleMultiAxisConstraint({ draggableDirections, newPosition, originPosition })
    } else if (diagonalLines.length > 0 && !hasVertical && !hasHorizontal && diagonals.length === 0) {
      constrainedPosition = handleDiagonalLineConstraint({ diagonalLines, newPosition, originPosition })
    } else if (hasVertical && !hasHorizontal && diagonals.length === 0 && diagonalLines.length === 0) {
      constrainedPosition = handleVerticalCardinalConstraint({ draggableDirections, newPosition, originPosition })
    } else if (hasHorizontal && !hasVertical && diagonals.length === 0 && diagonalLines.length === 0) {
      constrainedPosition = handleHorizontalCardinalConstraint({ draggableDirections, newPosition, originPosition })
    } else if (diagonals.length > 0 && !hasVertical && !hasHorizontal && diagonalLines.length === 0) {
      constrainedPosition = handleDiagonalConstraint({ diagonals, newPosition, originPosition })
    } else if (hasVertical && hasHorizontal && diagonals.length === 0 && diagonalLines.length === 0) {
      constrainedPosition = handleMixedCardinalConstraint({ draggableDirections, newPosition, originPosition })
    } else {
      constrainedPosition = originPosition
    }
  }

  // Then apply distance constraints if specified
  if (maxDistance !== undefined || minDistance !== undefined) {
    constrainedPosition = constrainByDistance({
      newPosition: constrainedPosition,
      originPosition,
      maxDistance,
      minDistance,
    })
  }

  return constrainedPosition
}

/**
 * Cursor mappings for draggable directions
 */
export const CURSORS = {
  n: 'n-resize',
  s: 's-resize',
  e: 'e-resize',
  w: 'w-resize',
  ne: 'ne-resize',
  nw: 'nw-resize',
  se: 'se-resize',
  sw: 'sw-resize',
  ns: 'ns-resize',
  ew: 'ew-resize',
  nesw: 'nesw-resize',
  nwse: 'nwse-resize',
  'e,s,w': 's-resize',
  'e,n,w': 'n-resize',
  'e,n,s': 'e-resize',
  'n,s,w': 'w-resize',
  grab: 'grab',
}

/**
 * Determines the appropriate cursor based on draggable state and directions
 *
 * @param {Object} params
 * @param {boolean} params.draggable - Whether the marker is draggable
 * @param {Array<string>} params.draggableDirections - Array of direction strings
 * @param {boolean} params.interactable - Whether the marker is interactable
 * @param {boolean} params.isGrabbing - Whether currently dragging
 * @returns {string} The cursor CSS value
 */
export function getCursor({ draggable, draggableDirections, interactable, isGrabbing }) {
  // If has draggableDirections, determine cursor based on directions (even when grabbing)
  if (draggable && draggableDirections && draggableDirections.length > 0) {
    // Single direction
    if (draggableDirections.length === 1) {
      const dir = draggableDirections[0]
      return CURSORS[dir] || CURSORS.grab
    }

    // Multiple directions - determine cursor based on combination
    const sorted = [...draggableDirections].sort().join(',')

    // Same axis pairs
    if (sorted === 'n,s') return CURSORS.ns
    if (sorted === 'e,w') return CURSORS.ew

    // Diagonal line pairs
    if (sorted === 'ne,sw') return CURSORS.nesw
    if (sorted === 'nw,se') return CURSORS.nwse

    // Two cardinals on different axes (quadrant resize)
    if (sorted === 'e,n') return CURSORS.ne
    if (sorted === 'n,w') return CURSORS.nw
    if (sorted === 'e,s') return CURSORS.se
    if (sorted === 's,w') return CURSORS.sw

    // Three cardinals - specific cursors
    if (CURSORS[sorted]) return CURSORS[sorted]

    // Default fallback for draggable with directions
    return CURSORS.grab
  }

  // Standard cursor logic (no draggableDirections)
  if (isGrabbing) return 'grabbing'
  if (draggable) return 'grab'
  if (interactable) return 'pointer'

  return 'inherit'
}

/**
 * PropTypes validator for draggableDirections
 *
 * Internal Only
 *
 * The directions in which the marker can be dragged.
 *
 * Cardinals:
 * - Single (Line): ['e'], ['n'], ['s'], ['w']
 * - Two same axis (Line): ['e', 'w']†, ['n', 's']‡
 * - Two different axes (Quadrant): ['e', 'n'], ['e', 's'], ['n', 'w'], ['s', 'w']
 * - Three (hemisphere): ['e', 's', 'w'], ['e', 'n', 'w'], ['e', 'n', 's'], ['n', 's', 'w']
 *
 * Multi-Axis:
 * - Single same axis - Horizontal (Line) - ['ew']†
 * - Single same axis - Vertical (Line) - ['ns']‡
 *
 * Diagonals:
 * - Single (Line): ['ne'], ['nw'], ['se'], ['sw']
 * - Pairs (Line): ['ne', 'sw']§, ['nw', 'se']¶
 *
 * Diagonal Lines:
 * - Groups (Line): ['nesw']§, ['nwse']¶
 *
 * †, ‡, §, ¶: Mark combinations that are functionally equivalent.
 */
export function draggableDirectionsValidator(props, propName, componentName) {
  const directions = props[propName]

  if (!directions || directions.length === 0) {
    return null
  }

  const cardinals = new Set(['n', 's', 'e', 'w'])
  const multiAxis = new Set(['ns', 'ew'])
  const diagonals = new Set(['ne', 'nw', 'se', 'sw'])
  const diagonalLines = new Set(['nesw', 'nwse'])

  const hasCardinal = directions.some((direction) => cardinals.has(direction))
  const hasMultiAxis = directions.some((direction) => multiAxis.has(direction))
  const hasDiagonal = directions.some((direction) => diagonals.has(direction))
  const hasDiagonalLine = directions.some((direction) => diagonalLines.has(direction))

  const typeCount = [hasCardinal, hasMultiAxis, hasDiagonal, hasDiagonalLine].filter(Boolean).length

  if (typeCount > 1) {
    return new Error(
      `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
        `Cannot mix different direction types (cardinals: n/s/e/w, multi-axis: ns/ew, diagonals: ne/nw/se/sw, diagonal-lines: nesw/nwse). ` +
        `Received: [${directions.join(', ')}]`
    )
  }

  if (hasCardinal) {
    const cardinalDirections = directions.filter((direction) => cardinals.has(direction))
    if (cardinalDirections.length === 4) {
      return new Error(
        `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
          `All four cardinal directions (n, s, e, w) are not allowed. Use fewer directions. ` +
          `Received: [${directions.join(', ')}]`
      )
    }
  }

  if (hasMultiAxis && directions.includes('ns') && directions.includes('ew')) {
    return new Error(
      `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
        `Both 'ns' and 'ew' together are not allowed (creates unrestricted movement). ` +
        `Received: [${directions.join(', ')}]`
    )
  }

  if (hasDiagonal) {
    const diagonalDirections = directions.filter((direction) => diagonals.has(direction))
    const sorted = diagonalDirections.sort().join(',')
    const validDiagonalCombos = new Set(['ne', 'nw', 'se', 'sw', 'ne,sw', 'nw,se'])
    if (!validDiagonalCombos.has(sorted)) {
      return new Error(
        `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
          `For diagonals, only single directions (ne, nw, se, sw) or opposite pairs (ne+sw, nw+se) are allowed. ` +
          `Received: [${directions.join(', ')}]`
      )
    }
  }

  if (hasDiagonalLine && directions.length > 1) {
    return new Error(
      `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
        `Diagonal-lines (nesw, nwse) cannot be combined with other directions. ` +
        `Received: [${directions.join(', ')}]`
    )
  }

  return null
}
