import React, {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react'
import { css, cx } from '@linaria/core'
import { colors, IconButton, Row, useOverlay } from '@fs/zion-ui'
import { Popper, useAutoFocus } from '@fs/zion-ui/quarks-authorized-use-only'
import PropTypes from 'prop-types'
import { i18n } from '@fs/zion-locale'
import { MenuClose } from '@fs/zion-icon'
import { useRandomId } from '@fs/zion-frontend-friends'
import useMap from './useMap'

const TRANSITION_DURATION_MS = 300
const DELAY_DURATION_MS = 100
const DEFAULT_CLOSE_OPTIONS = { immediate: false }

const sharedPopperClassName = css`
  max-inline-size: calc(100% - 16px);
  z-index: 4;
`

const labelClassName = css`
  // The need for this is most noticeable when rapidly moving your mouse back and forth over a boundary.
  pointer-events: none;
`

const popperClassName = css`
  background: ${colors.gray00};
  border-radius: 4px;
  box-shadow:
    0px 5px 5px -3px rgba(0, 0, 0, 0.2),
    0px 8px 10px 1px rgba(0, 0, 0, 0.14),
    0px 3px 14px 2px rgba(0, 0, 0, 0.12);
  color: ${colors.gray100};
  display: block;
  font-size: 13px;
  inline-size: max-content;
  max-inline-size: 100%;
  opacity: 1;
  overflow: hidden;
  padding: 4px 8px;
  transition-behavior: allow-discrete;
  transition-property: opacity, display;

  @starting-style {
    opacity: 0;
  }
`

const hiddenClassName = css`
  display: none;
  opacity: 0;
`

const SharedPopperContext = createContext()

export default function useSharedPopper() {
  const context = useContext(SharedPopperContext)

  if (!context) {
    throw new Error('useSharedPopper must be used within a SharedPopperProvider')
  }

  return context
}

export const SharedPopperProvider = forwardRef(({ children, onInfoClosed, updateHandler }, ref) => {
  const { mapContainer } = useMap()
  const [info, setInfo] = useState()
  const [label, setLabel] = useState()
  const [target, setTarget] = useState()
  const [transitioning, setTransitioning] = useState(false)
  const overlay = useOverlay()
  const overlayRef = useRef(overlay)
  const instanceRef = useRef()
  const lastPositionRef = useRef({ x: 0, y: 0 })
  const transitionTimeoutRef = useRef()
  const delayTimeoutRef = useRef()
  const isInfoOpenRef = useRef(false)
  const isLabelOpenRef = useRef(false)
  const onInfoChangedHandlersRef = useRef([])
  const onInfoClosedHandlersRef = useRef([])
  const onInfoClosedRef = useRef(onInfoClosed)
  const containerRef = useRef()
  const closeButtonId = useRandomId()
  const previousInfoRef = useRef(info)
  const [shouldAutoFocus, setShouldAutoFocus] = useState(false)
  const [focusTrigger, setFocusTrigger] = useState(0)

  useAutoFocus({
    isOpen: Boolean(info),
    enabled: shouldAutoFocus,
    containerRef,
    whatToFocusInContainer: (container) => {
      // Look for any focusable element first (excluding the close button)
      const focusableElement = container.querySelector(
        `button:not([disabled]):not(#${closeButtonId}), [href], input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])`
      )

      // If found, return it; otherwise fall back to the close button
      return focusableElement || container.querySelector(`#${closeButtonId}`)
    },
  })

  // Keep onInfoClosedRef in sync with the latest callback
  useEffect(() => {
    onInfoClosedRef.current = onInfoClosed
  }, [onInfoClosed])

  // Track when info changes or when focusTrigger changes (same marker clicked again)
  useEffect(() => {
    const infoChanged = previousInfoRef.current !== info
    previousInfoRef.current = info

    if (Boolean(info) && (infoChanged || focusTrigger > 0)) {
      setShouldAutoFocus(true)
    }
  }, [info, focusTrigger])

  // Reset auto-focus flag after it's been used
  useEffect(() => {
    if (shouldAutoFocus && info) {
      setShouldAutoFocus(false)
    }
  }, [shouldAutoFocus, info])

  function open({ info: newInfo, label: newLabel, target: newTarget }) {
    if (!newInfo && !newLabel) {
      return
    }

    clearTimeout(delayTimeoutRef.current)
    clearTimeout(transitionTimeoutRef.current)
    setTransitioning(true)

    setTarget(
      newTarget
        ? { current: newTarget }
        : {
            current: {
              getBoundingClientRect: () => {
                const { x, y } = lastPositionRef.current

                if (x === undefined && y === undefined) {
                  return { bottom: 0, height: 0, left: -9999, right: 0, top: -9999, width: 0 }
                }

                return { bottom: y, height: 0, left: x, right: x, top: y, width: 0 }
              },
            },
          }
    )

    if (newInfo) {
      isInfoOpenRef.current = true
      setInfo(newInfo)
      // Trigger focus whenever info is opened (even if same content)
      setFocusTrigger((prev) => prev + 1)
    }

    if (newLabel) {
      isLabelOpenRef.current = true
      setLabel(newLabel)
    }

    overlayRef.current.open()

    transitionTimeoutRef.current = setTimeout(() => {
      setTransitioning(false)
    }, TRANSITION_DURATION_MS)
  }

  function close({ immediate } = DEFAULT_CLOSE_OPTIONS) {
    clearTimeout(delayTimeoutRef.current)

    // Give a short delay so that if a marker is clicked and gains focus
    // the popper doesn't close and then immediately open again.
    delayTimeoutRef.current = setTimeout(
      () => {
        clearTimeout(transitionTimeoutRef.current)

        setTransitioning(true)

        overlayRef.current.close()

        transitionTimeoutRef.current = setTimeout(
          () => {
            setTransitioning(false)
          },
          immediate ? 0 : TRANSITION_DURATION_MS
        )
      },
      immediate ? 0 : DELAY_DURATION_MS
    )
  }

  function update({ event }) {
    lastPositionRef.current = {
      x: event.clientX,
      y: event.clientY,
    }

    if (instanceRef.current) {
      instanceRef.current.update()
    }
  }

  function addOnInfoChangedHandler(handler) {
    onInfoChangedHandlersRef.current.push(handler)
  }

  function callInfoChangedHandlers() {
    onInfoChangedHandlersRef.current.forEach((handler) => handler())
    onInfoChangedHandlersRef.current = []
  }

  function addOnInfoClosedHandler({ handler, id }) {
    if (onInfoClosedHandlersRef.current.some(({ id: handlerId }) => handlerId === id)) {
      return
    }

    onInfoClosedHandlersRef.current.push({ handler, id })
  }

  function callInfoClosedHandlers({ shouldCallOnInfoClosed }) {
    onInfoClosedHandlersRef.current.forEach(({ handler }) => handler())
    onInfoClosedHandlersRef.current = []

    if (shouldCallOnInfoClosed && onInfoClosedRef.current) {
      onInfoClosedRef.current()
    }
  }

  const closeOverlay = useCallback(() => {
    clearTimeout(delayTimeoutRef.current)
    clearTimeout(transitionTimeoutRef.current)

    const hasPendingInfoClosedHandlers = onInfoClosedHandlersRef.current.length > 0
    const shouldCallOnInfoClosed = isInfoOpenRef.current || hasPendingInfoClosedHandlers

    isInfoOpenRef.current = false
    isLabelOpenRef.current = false
    setInfo(undefined)
    setLabel(undefined)

    setTransitioning(false)

    overlayRef.current.close()

    callInfoChangedHandlers()
    callInfoClosedHandlers({ shouldCallOnInfoClosed })
  }, [])

  useImperativeHandle(
    ref,
    () => ({
      closeOverlay,
    }),
    [closeOverlay]
  )

  const value = useMemo(
    () => ({
      addOnInfoChangedHandler,
      callInfoChangedHandlers,
      addOnInfoClosedHandler,
      callInfoClosedHandlers,
      close,
      isInfoOpenRef,
      isLabelOpenRef,
      open,
      update,
    }),
    []
  )

  const keyUpHandler = useCallback(
    (event) => {
      if (event.key === 'Escape') {
        closeOverlay()
        target?.current?.focus?.()
      }
    },
    [closeOverlay, target]
  )

  // Keep the latest overlay instance without forcing consumers to rebind callbacks.
  useEffect(() => {
    overlayRef.current = overlay
  }, [overlay])

  // Setup event listeners
  useEffect(() => {
    window.addEventListener('keyup', keyUpHandler)
    window.parent?.addEventListener('keyup', keyUpHandler)

    return () => {
      window.removeEventListener('keyup', keyUpHandler)
      window.parent?.removeEventListener('keyup', keyUpHandler)
    }
  }, [keyUpHandler])

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      clearTimeout(delayTimeoutRef.current)
      clearTimeout(transitionTimeoutRef.current)
    }
  }, [])

  // A callback to update the popper position or close the popper when the map is being dragged.
  const callback = useMemo(
    () => () => {
      if (isInfoOpenRef.current && target?.current) {
        const { bottom, left, right, top } = target.current.getBoundingClientRect()
        const offsetWidth = target.current.offsetWidth || 0
        const offsetHeight = target.current.offsetHeight || 0

        // Note: Clustering removes the marker from the DOM when it is outside the cluster bounds, so we need to check if it still has dimensions.
        if (bottom !== 0 && left !== 0 && right !== 0 && top !== 0 && offsetWidth !== 0 && offsetHeight !== 0) {
          update({
            event: {
              clientX: left + offsetWidth / 2,
              clientY: top + offsetHeight / 2,
            },
          })
        }
      } else if (isLabelOpenRef.current) {
        overlayRef.current.close()
      }
    },
    [target]
  )

  // Clustering removes the marker from the DOM when it is outside the cluster bounds, so we need to check if it's still connected.
  // This also handles closing the popper if the `userLocation` marker is removed.
  useEffect(() => {
    // Only set up observer if target exists and is a marker
    if (!target?.current || !target?.current?.nodeType) {
      return undefined
    }

    if (!mapContainer?.current || typeof MutationObserver === 'undefined') {
      return undefined
    }

    const NodeConstructor =
      mapContainer.current?.ownerDocument?.defaultView?.Node ?? (typeof Node !== 'undefined' ? Node : undefined)

    if (!NodeConstructor || !(mapContainer.current instanceof NodeConstructor)) {
      return undefined
    }

    let timeoutId

    const observer = new MutationObserver((mutations) => {
      clearTimeout(timeoutId)

      timeoutId = setTimeout(() => {
        const targetIsDisconnected = !target.current?.isConnected

        let targetHasBeenRemoved = false
        if (!targetIsDisconnected) {
          targetHasBeenRemoved = mutations.some((mutation) => {
            if (mutation.type === 'childList') {
              return Array.from(mutation.removedNodes).some((removedNode) => {
                return removedNode === target.current || removedNode.contains?.(target.current)
              })
            }

            return false
          })
        }

        if (targetIsDisconnected || targetHasBeenRemoved) {
          close({ immediate: true })
        }
      }, 50)
    })

    try {
      observer.observe(mapContainer.current, { childList: true, subtree: true })
    } catch {
      clearTimeout(timeoutId)
      observer.disconnect()

      return undefined
    }

    return () => {
      clearTimeout(timeoutId)
      observer.disconnect()
    }
  }, [mapContainer, target])

  // Register the callback with the update handler
  useEffect(() => {
    updateHandler.add(callback)

    return () => {
      updateHandler.remove(callback)
    }
  }, [callback, updateHandler])

  return (
    <SharedPopperContext.Provider value={value}>
      {children}
      <Popper
        centerPlacement
        className={cx(sharedPopperClassName, !info && label && labelClassName, !overlay.isOpen && hiddenClassName)}
        instanceRef={instanceRef}
        isOpen={overlay.isOpen}
        placement={['top', 'bottom', 'left', 'right']}
        targetRef={target || { current: null }}
        transitioning={transitioning}
      >
        <div
          className={popperClassName}
          ref={containerRef}
          // Note: The <dialog /> element was implemented here but it carries a lot of baggage from the browser.
          // It was a much better experience to just use a div with role="dialog" or "tooltip".
          // In particular transitioning from the `info` to the `label` works a lot better this way.
          role={info ? 'dialog' : 'tooltip'}
          style={{
            transitionDuration: `${TRANSITION_DURATION_MS}ms`,
          }}
        >
          {info && (
            <Row alignItemsY="middle" alignX="end">
              <IconButton
                color="gray"
                description={i18n.t('common-ui:close.action')}
                Icon={MenuClose}
                id={closeButtonId}
                onClick={() => {
                  closeOverlay()
                  target?.current?.focus?.()
                }}
                size="sm"
              />
            </Row>
          )}
          {info || label}
        </div>
      </Popper>
    </SharedPopperContext.Provider>
  )
})

SharedPopperProvider.displayName = 'SharedPopperProvider'

SharedPopperProvider.propTypes = {
  children: PropTypes.node.isRequired,
  onInfoClosed: PropTypes.func,
  updateHandler: PropTypes.shape({
    add: PropTypes.func.isRequired,
    remove: PropTypes.func.isRequired,
  }).isRequired,
}
